def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0 or np.isnan(ratio):
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += ((-1)**k) * (ratio ** (2 * k)) / (k**2 + 3)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + 2 * j + 1))
            score = (ratio ** 6) / 3 + penalty
            if item > 2 * capacity:
                score *= 4
            else:
                score *= 3
            for _ in range(3):
                score += np.log1p(abs(score)) * 0.5
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                score += sign * (ratio ** x) / (x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score + np.sqrt(abs(score))
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 30 if ratio < 2.5 else 20
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 3
            for n in range(2, 5):
                score /= (1 + np.log(n + ratio))
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp = 0
            for p in range(1, 18):
                if p % 5 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 3 == 0:
                    temp -= (ratio ** p) / (p * 6)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 40 if ratio < 1.3 else 25 if ratio < 1.6 else 12
            score = abs(temp) * multiplier
            if ratio > 1.85:
                extra = 0
                for m in range(1, 9):
                    extra += (ratio ** m) / (m + 4)
                score += extra * 3
            for a in range(1, 4):
                score *= (1 - 1 / (a + ratio + 1.5))
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 2 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                else:
                    temp_score -= (ratio ** p) / (p * 3)
            if ratio < 0.3:
                multiplier = 40
            elif ratio < 0.5:
                multiplier = 30
            elif ratio < 0.7:
                multiplier = 20
            elif ratio < 0.9:
                multiplier = 15
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier
            if ratio > 0.75:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            for b in range(1, 5):
                decay *= (1 - 1 / (ratio + b + 0.5))
            priorities[i] = score * decay
        else:
            priorities[i] = np.inf
        if not np.isinf(priorities[i]):
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (bins[i] + 2))
            priorities[i] *= factor
            adjustment = 0.0
            for c in range(1, 5):
                adjustment += np.sin(ratio * c) / (c + 1)
            priorities[i] += abs(adjustment)
            if item > capacity:
                priorities[i] *= (1 + np.log1p(item - capacity))
    return priorities
